import 'dart:io';
List<int> solveCase(String s, List<String> words){ if(words.isEmpty) return []; int wlen=words[0].length,total=wlen*words.length; var target=[...words]..sort(); List<int> ans=[]; for(int i=0;i+total<=s.length;i++){ var parts=List.generate(words.length,(j)=>s.substring(i+j*wlen,i+(j+1)*wlen))..sort(); bool ok=true; for(int j=0;j<parts.length;j++){ if(parts[j]!=target[j]) { ok=false; break; } } if(ok) ans.add(i);} return ans; }
void main(){ final lines=File('/dev/stdin').readAsStringSync().split(RegExp(r'\r?\n')); if(lines.isEmpty||lines.first.trim().isEmpty) return; int idx=0,t=int.parse(lines[idx++].trim()); List<String> out=[]; for(int tc=0;tc<t;tc++){ String s=idx<lines.length?lines[idx++]:''; int m=idx<lines.length?int.parse(lines[idx++].trim()):0; List<String> words=List.generate(m,(_)=>idx<lines.length?lines[idx++]:''); out.add('['+solveCase(s,words).join(',')+']'); } stdout.write(out.join('\n')); }
